# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using Microsoft.EntityFrameworkCore;

public class ApplicationDbContext : DbContext
{
    public DbSet<Ticket> Tickets { get; set; }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseSqlServer(@"Your_Connection_String");
    }
}

public class Ticket
{
    public int Id { get; set; }
    public int EventId { get; set; }
    public int SeatNumber { get; set; }
    public bool IsBooked { get; set; }
}

public async Task PurchaseTicketsAsync(int eventId, List<int> seatNumbers, int quantity)
{
    using (var context = new ApplicationDbContext())
    {
        var availableSeats = await context.Tickets
            .Where(t => t.EventId == eventId && !t.IsBooked)
            .ToListAsync();

        if (seatNumbers.Count > availableSeats.Count || quantity > seatNumbers.Count)
        {
            throw new Exception("Invalid seat numbers or purchase quantity.");
        }

        var ticketsToUpdate = new List<Ticket>();

        foreach (var seatNumber in seatNumbers)
        {
            var ticket = availableSeats.FirstOrDefault(t => t.SeatNumber == seatNumber);

            if (ticket != null)
            {
                ticket.IsBooked = true;
                ticketsToUpdate.Add(ticket);
            }
        }

        await context.SaveChangesAsync();
    }
}